<?php namespace App\Repositories\Alumni;use App\Repositories\BaseRepository;use App\Models\Alumni\AlumniEvent;use Illuminate\Database\Eloquent\Collection;class AlumniEventRepository extends BaseRepository{    public function __construct(AlumniEvent $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getUpcomingEvents(int $limit = 10): Collection    {        return $this->query()->where('event_date', '>=', now())->where('status', 'published')->orderBy('event_date', 'asc')->limit($limit)->get();    }    public function getPastEvents(): Collection    {        return $this->query()->where('event_date', '<', now())->orderBy('event_date', 'desc')->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('event_date', [$startDate, $endDate])->get();    }    public function getByType(string $type): Collection    {        return $this->findByField('event_type', $type);    }    public function searchEvents(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->orWhere('venue', 'like', "%{$keyword}%")->get();    }    public function countAttendees(int $eventId): int    {        return $this->query()->where('id', $eventId)->withCount('attendees')->first()->attendees_count ?? 0;    }    public function getEventWithAttendees(int $eventId): ?AlumniEvent    {        return $this->query()->with('attendees')->findOrFail($eventId);    }    public function publish(int $id): bool    {        return $this->update($id, ['status' => 'published', 'published_at' => now()]);    }    public function cancel(int $id, string $reason = null): bool    {        $data = ['status' => 'cancelled'];        if ($reason) {            $data['cancellation_reason'] = $reason;        }        return $this->update($id, $data);    }}